import { strictEqual, ok } from "node:assert";
import { withDb } from "../src/db.mjs";
import { ensureSchema } from "../src/schema.mjs";
import { createAccounts, getAccounts, updateAccounts, deleteAccounts } from "../src/accounts.mjs";

await withDb(async (client) => {
  await ensureSchema(client);

  const created = await createAccounts(client, {
    accountId: "test-accountId", name: "test-name", tier: "strategic", status: "active",
  });
  ok(created.accountId, "create returns a document with an id");

  // verify directly in the live DB
  const liveRow = (await client.query('SELECT * FROM accounts WHERE account_id = $1', [created.accountId])).rows[0];
  ok(liveRow, "live DB has the created row");
  strictEqual(liveRow.name, created.name, "live DB row matches handler response");

  const read = await getAccounts(client, created.accountId);
  ok(read, "get returns the document");
  strictEqual(read.name, created.name, "read matches created");

  const updated = await updateAccounts(client, created.accountId, { name: "updated-name" });
  strictEqual(updated.name, "updated-name", "update returns updated doc");

  const liveUpdated = (await client.query('SELECT * FROM accounts WHERE account_id = $1', [created.accountId])).rows[0];
  strictEqual(liveUpdated.name, "updated-name", "live DB reflects the update");

  const deleted = await deleteAccounts(client, created.accountId);
  ok(deleted, "delete returns true");

  const liveDeleted = (await client.query('SELECT * FROM accounts WHERE account_id = $1', [created.accountId])).rows[0];
  ok(!liveDeleted, "live DB no longer has the row");
});

